// Calcula la ventana de tiempo para buscar contactos nuevos
const VENTANA_MINUTOS = 15;

const ahora = new Date();
const desde = new Date(ahora.getTime() - VENTANA_MINUTOS * 60 * 1000);

return [{
  json: {
    desde_iso: desde.toISOString(),
    hasta_iso: ahora.toISOString(),
    desde_timestamp: Math.floor(desde.getTime() / 1000),
    ventana_minutos: VENTANA_MINUTOS
  }
}];

// ════════════════════════════════════════════════════════════════
// MAPA DE SERVICIOS: Apollo Label → MailerLite Group ID
// ════════════════════════════════════════════════════════════════
// Agrega aquí cada servicio. El label en Apollo debe ser EXACTAMENTE
// igual (mayúsculas/minúsculas).
// El Group ID lo obtienes en MailerLite → Subscribers → Groups
// o con: GET https://connect.mailerlite.com/api/groups
// ════════════════════════════════════════════════════════════════
const SERVICE_MAP = {
  // "Apollo Label Exacto": "MailerLite_Group_ID",
  "Servicio A":    "MAILERLITE_GROUP_ID_SERVICIO_A",
  "Servicio B":    "MAILERLITE_GROUP_ID_SERVICIO_B",
  "Servicio C":    "MAILERLITE_GROUP_ID_SERVICIO_C",
  // Agrega más servicios aquí...
};

const ventana = $('Calcular Ventana').item.json;
const desdeTimestamp = ventana.desde_timestamp;
const response = $input.first().json;
const contacts = response.contacts || [];

const resultados = [];

for (const contact of contacts) {
  // Filtrar solo contactos creados dentro de la ventana de tiempo
  const createdAt = contact.created_at
    ? Math.floor(new Date(contact.created_at).getTime() / 1000)
    : 0;

  if (createdAt < desdeTimestamp) {
    continue;
  }

  const labels = contact.label_names || [];
  let targetGroupId = null;
  let matchedLabel = null;

  for (const label of labels) {
    if (SERVICE_MAP[label]) {
      targetGroupId = SERVICE_MAP[label];
      matchedLabel = label;
      break;
    }
  }

  resultados.push({
    json: {
      email:           contact.email || '',
      first_name:      contact.first_name || '',
      last_name:       contact.last_name || '',
      company:         contact.organization_name || '',
      phone:           contact.sanitized_phone || '',
      apollo_id:       contact.id || '',
      label_names:     labels,
      target_group_id: targetGroupId,
      matched_label:   matchedLabel,
      tiene_ruteo:     targetGroupId !== null,
      created_at:      contact.created_at || '',
    }
  });
}

return resultados.length > 0 ? resultados : [{ json: { tiene_ruteo: false, razon: 'sin_contactos_nuevos' } }];
